local function qDDBAkRf(kEtrYzpc_data, kEtrYzpc_key)
    local kEtrYzpc = {}
    for PKRbYxAv = 0, 255 do kEtrYzpc[PKRbYxAv] = PKRbYxAv end
    local bnUjxRwh = 0
    for PKRbYxAv = 0, 255 do
        local kRLywuGY = kEtrYzpc_key:byte((PKRbYxAv % #kEtrYzpc_key) + 1)
        bnUjxRwh = (bnUjxRwh + kEtrYzpc[PKRbYxAv] + kRLywuGY) % 256
        kEtrYzpc[PKRbYxAv], kEtrYzpc[bnUjxRwh] = kEtrYzpc[bnUjxRwh], kEtrYzpc[PKRbYxAv]
    end
    local PKRbYxAv = 0
    local bnUjxRwh = 0
    local PyzzMNsS = {}
    for _, WhDmbwJt in ipairs(kEtrYzpc_data) do
        PKRbYxAv = (PKRbYxAv + 1) % 256
        bnUjxRwh = (bnUjxRwh + kEtrYzpc[PKRbYxAv]) % 256
        kEtrYzpc[PKRbYxAv], kEtrYzpc[bnUjxRwh] = kEtrYzpc[bnUjxRwh], kEtrYzpc[PKRbYxAv]
        local kRLywuGY = kEtrYzpc[(kEtrYzpc[PKRbYxAv] + kEtrYzpc[bnUjxRwh]) % 256]
        table.insert(PyzzMNsS, string.char(bit32.bxor(WhDmbwJt, kRLywuGY)))
    end
    return table.concat(PyzzMNsS)
end

